const pattern = /^(@[\w-]+\/)?nodebb-(theme|plugin|widget|rewards)-[\w-]+$/;

const tests = [
  { input: '\t\nnodebb-plugin', expected: false },
  { input: 'notaplugin', expected: false },
  { input: 'nodebb-plugin-test', expected: true },
  { input: '@nodebb/nodebb-plugin-test', expected: true },
  { input: 'nodebb-theme-test', expected: true },
];

tests.forEach(test => {
  const result = pattern.test(test.input);
  const status = result === test.expected ? '✓' : '✗';
  console.log(\`\${status} '\${test.input}' => \${result} (expected: \${test.expected})\`);
});
"

